const now = new Date();
const results = [];

const MESES = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
const DIAS = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];

function fechaLegible(year, month, day) {
  const d = new Date(year, month - 1, day);
  return `${DIAS[d.getDay()]} ${day} de ${MESES[month - 1]} de ${year}`;
}

function horaLegible(horaRaw) {
  // Devuelve "18:00" o "18:00h" limpio
  return horaRaw.trim();
}

for (const item of $input.all()) {
  const cita = item.json;

  // Solo citas activas
  if (!cita.ESTADO || cita.ESTADO.toLowerCase() !== 'activa') continue;

  // Datos obligatorios
  if (!cita.FECHA_CITA || !cita.HORA || !cita.TELEFONO) continue;

  // Parsear fecha
  const fechaRaw = String(cita.FECHA_CITA).trim();
  const horaRaw = String(cita.HORA).trim();

  let year, month, day;
  if (fechaRaw.includes('-')) {
    [year, month, day] = fechaRaw.split('-').map(Number);
  } else if (fechaRaw.includes('/')) {
    const parts = fechaRaw.split('/');
    if (parts[0].length === 4) {
      [year, month, day] = parts.map(Number);
    } else {
      [day, month, year] = parts.map(Number);
    }
  } else {
    continue;
  }

  const [hours, minutes] = horaRaw.split(':').map(Number);
  if (isNaN(year) || isNaN(month) || isNaN(day) || isNaN(hours)) continue;

  // Fecha de la cita en Madrid (UTC+1)
  const citaDate = new Date(Date.UTC(year, month - 1, day, hours - 1, minutes || 0));
  const diffMs = citaDate - now;
  const diffHours = diffMs / (1000 * 60 * 60);

  const idioma = (cita.IDIOMA || 'español').toLowerCase().includes('ingl') ? 'english' : 'español';
  const club = cita.CLUB || 'el club';
  const fechaStr = fechaLegible(year, month, day);
  const horaStr = horaLegible(horaRaw);

  // RECORDATORIO 48H — entre 47h y 49h antes, no enviado aún
  if (diffHours >= 47 && diffHours <= 49 && !cita.REMINDER_48H_ENVIADO) {
    const mensaje = idioma === 'english'
      ? `Your admission process is going smoothly and we are looking forward to welcoming you. We have already approved your membership, so the hardest step is done.\n\nYou just need to come to the "${club}" association for the final signing of your registration and closing of your file. It will only take a moment!\n\nWe will see you on ${fechaStr} at ${horaStr}.\n\nGet that membership card ready! We are sure you will enjoy being part of our community.\n\nBest regards,\nThe WD Team`
      : `Tu proceso de admisión va viento en popa y estamos deseando que te unas a nosotros. Ya te hemos avalado, así que el paso más complicado está hecho.\n\nSolo necesitamos que te acerques a la asociación "${club}" para la firma final de tu registro y el cierre del expediente. ¡Será un momento muy breve!\n\nTe esperamos el ${fechaStr} a las ${horaStr}.\n\n¡Prepara ese carnet de socio! Estamos seguros de que disfrutarás mucho siendo parte de nuestra comunidad.\n\nUn saludo muy cordial,\nEl equipo de WD`;

    results.push({
      json: { ...cita, tipoRecordatorio: '48h', idioma, mensaje }
    });
  }

  // RECORDATORIO 2H — entre 1.5h y 2.5h antes, no enviado aún
  else if (diffHours >= 1.5 && diffHours <= 2.5 && !cita.REMINDER_2H_ENVIADO) {
    const mensaje = idioma === 'english'
      ? `We are very happy that you have decided to join "${club}". As we informed you by email, we have already processed your endorsement and now there is just one last step to officially welcome you.\n\nWe will see you on ${fechaStr} at ${horaStr} at the association. It is a very quick and necessary step to complete your registration.\n\nSee you soon!\nThe WD Team`
      : `Estamos muy contentos de que hayas decidido unirte a "${club}". Como te informamos por email, ya hemos tramitado tu aval y ahora solo queda un último paso para darte la bienvenida oficial.\n\nTe esperamos el ${fechaStr} a las ${horaStr} en la asociación. Es un paso muy rápido y necesario para completar tu registro.\n\n¡Nos vemos pronto!\nEl equipo de WD`;

    results.push({
      json: { ...cita, tipoRecordatorio: '2h', idioma, mensaje }
    });
  }

  // FEEDBACK — entre 23h y 25h DESPUÉS, no enviado aún
  else if (diffHours >= -25 && diffHours <= -23 && !cita.FEEDBACK_ENVIADO) {
    const mensaje = idioma === 'english'
      ? `Hello! We hope you enjoyed your visit to ${club}. Could you tell us how your experience was?\n\nYour opinion helps us improve and offer an even better service to all our members.\n\nThank you for being part of our community!\nThe WD Team`
      : `¡Hola! Esperamos que hayas disfrutado tu visita a ${club}. ¿Podrías contarnos cómo fue tu experiencia?\n\nTu opinión nos ayuda a mejorar y a ofrecer un servicio aún mejor a todos nuestros socios.\n\n¡Gracias por ser parte de nuestra comunidad!\nEl equipo de WD`;

    results.push({
      json: { ...cita, tipoRecordatorio: 'feedback', idioma, mensaje }
    });
  }
}

return results;

return $input.all().map(item => {
  const tipo = item.json.tipoRecordatorio;
  const update = { TELEFONO: item.json.TELEFONO };
  if (tipo === '48h') update.REMINDER_48H_ENVIADO = 'TRUE';
  if (tipo === '2h') update.REMINDER_2H_ENVIADO = 'TRUE';
  if (tipo === 'feedback') update.FEEDBACK_ENVIADO = 'TRUE';
  return { json: update };
});
